class Solution:
    def levelOrder(self, root: Node) -> List[List[int]]:
        if not root: return []
        ans, q = [], deque([root])
        while q:
            level, n = [], len(q)
            for _ in range(n):
                node = q.popleft()
                level.append(node.val)
                q.extend(node.children)
            ans.append(level)
        return ans

