class Solution {
public:
    vector<vector<int>> levelOrder(Node* root) {
        vector<vector<int>> ans;
        if (!root) return ans;
        queue<Node*> q; q.push(root);
        while (!q.empty()) {
            int sz=q.size(); vector<int> level;
            while(sz--){
                Node* cur=q.front(); q.pop();
                level.push_back(cur->val);
                for(Node* ch:cur->children) q.push(ch);
            }
            ans.push_back(level);
        }
        return ans;
    }
};
